class AnalyticsManager{constructor(){this._analytics=null}init(){if(window._firebaseConfigured)try{this._analytics=firebase.analytics(),console.info("[Analytics] Initialized")}catch(e){console.warn("[Analytics] Init error:",e)}}_log(e,t={}){if(this._analytics)try{this._analytics.logEvent(e,t)}catch(n){console.warn("[Analytics] logEvent error:",e,n)}}setUser(e){if(this._analytics)try{this._analytics.setUserId(e)}catch(t){}}lessonStart(e){this._log("lesson_start",{mode:e})}lessonComplete(e,t){this._log("lesson_complete",{mode:e,score:t})}xpGain(e,t="unknown"){var n,s,a;this._log("xp_gain",{amount:e,source:t,total_xp:(a=(s=(n=window.app)==null?void 0:n.state)==null?void 0:s.get("xp"))!=null?a:0})}levelUp(e){this._log("level_up",{level:e})}streakUpdate(e){this._log("streak_update",{streak:e})}speakingAttempt(e,t="en-US"){this._log("speaking_attempt",{score:e,accent:t})}screenView(e){this._log("screen_view",{screen_name:e})}achievementUnlocked(e){this._log("achievement_unlocked",{achievement_id:e})}}window.analyticsManager=new AnalyticsManager;window.addEventListener('error',function(e){window.analyticsManager&&window.analyticsManager._log('app_error',{msg:(e.message||'unknown').substring(0,150),src:(e.filename||'').split('/').pop().substring(0,50),line:e.lineno||0})});window.addEventListener('unhandledrejection',function(e){var _m=e.reason instanceof Error?e.reason.message:String(e.reason||'rejection');window.analyticsManager&&window.analyticsManager._log('app_error',{msg:_m.substring(0,150),src:'promise',line:0})});
